using Microsoft.EntityFrameworkCore;

class CosmosDbContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnConfiguring(DbContextOptionsBuilder options) =>
        options.UseCosmos(
            "AccountEndpoint=https://localhost:8081/;AccountKey=placeholder",
            "CatalogDb");

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");
            b.HasPartitionKey(p => p.Category);

            // EF Core 9 changed the default discriminator property from
            // "Discriminator" to "$type". Existing documents still store
            // "Discriminator", so we must keep the old name to avoid
            // runtime KeyNotFoundException on reads.
            b.HasDiscriminator<string>("Discriminator");
        });
    }
}

// EF Core 9 removed synchronous Cosmos DB query support.
// All queries must use async methods (ToListAsync, FirstAsync, etc.).
class ProductService
{
    private readonly CosmosDbContext _db;
    public ProductService(CosmosDbContext db) => _db = db;

    // BEFORE (EF Core 8 — now throws InvalidOperationException in 9):
    //   var products = _db.Products.Where(p => p.Category == cat).ToList();
    //
    // AFTER (EF Core 9):
    public async Task<List<Product>> GetByCategoryAsync(string cat) =>
        await _db.Products.Where(p => p.Category == cat).ToListAsync();
}

class Product
{
    public string Id { get; set; } = null!;
    public string Name { get; set; } = null!;
    public string Category { get; set; } = null!;
}

